void drawHeader(const char* text) {
  int w = tft.width();
  int headerHeight = 24;

  tft.fillRect(0, 0, w, headerHeight, TFT_DARKGREY);

  tft.setTextColor(TFT_PURPLE, TFT_DARKGREY);
  tft.setTextDatum(MC_DATUM);
  tft.setFreeFont(&FreeSerif9pt7b);
  tft.setTextSize(1);

  tft.drawString(text, w / 2, headerHeight / 2);
}

void drawBitmapCentered(uint16_t fg, uint16_t bg) {
  int x0 = (tft.width()  - IMG_WIDTH)  / 2;
  int y0 = (tft.height() - IMG_HEIGHT) / 2;

  tft.fillRect(x0, y0, IMG_WIDTH, IMG_HEIGHT, bg);

  for (int y = 0; y < IMG_HEIGHT; y++) {
    for (int x = 0; x < IMG_WIDTH; x++) {
      int byteIndex = y * BYTES_PER_ROW + (x / 8);
      uint8_t b = pgm_read_byte(&bitmap_oaxgj[byteIndex]);

      if (b & (0x80 >> (x % 8))) {
        tft.drawPixel(x0 + x, y0 + y, fg);
      }
    }
  }
}


